    for rec in hadith_data:
        for field in ['Matn','hadithTxt']:
            norm = normalize_ar((rec.get(field) or ''))
            if ns in norm:
                found_h.append((rec, field, rec.get(field)))
                break
    found_q=[]
    for rec in quran_data:
        norm = normalize_ar(rec.get('ayah_text',''))
        if ns in norm:
            found_q.append(rec)
    return found_h, found_q

